def getbit(bs, i):
    return (bs[i] >> 7) & 1

T = {0: bytearray(MAGIC), 1: bytearray(MAGIC)}
for iv in [0,1]:
    for idx in range(MAGIC):
        c1,d1 = getbit(K1,idx), getbit(K2,idx)
        c2,d2 = getbit(K3,idx), getbit(K4,idx)
        c3,d3 = getbit(K5,idx), getbit(K6,idx)
        good = None
        for x in [0,1]:
            ok = True
            for o in [0,1]:
                for k in [0,1]:
                    lhs = f(o, f(k, f(x, iv, c3, d3), c2, d2), c1, d1)
                    if lhs != (o ^ k):
                        ok = False
            if ok:
                good = x
                break
        if good is None:
            raise RuntimeError(f"no x for iv={iv} idx={idx}")
        T[iv][idx] = 0xff if good else 0x00

def solve():
    io = remote('rev.chal.csaw.io', 5000)
    data = io.recvuntil(b'\n', timeout=5)
    # read until random bits line appears
    blob = data + io.recvrepeat(0.5)
    m = re.search(rb"Enjoy this random bits : ([01]{73})", blob)
    if not m:
        # fallback line by line
        for _ in range(10):
            line = io.recvline(timeout=2) or b''
            blob += line
            m = re.search(rb"Enjoy this random bits : ([01]{73})", blob)
            if m:
                break
    if not m:
        raise RuntimeError(f"Failed to parse iv from: {blob!r}")
    iv = m.group(1).decode()

    payload = bytearray()
    for bit in iv:
        payload += T[1] if bit == '1' else T[0]
    assert len(payload) == MAGIC*MAGIC
    io.sendline(payload.hex().encode())
    out = io.recvall(timeout=5)
    txt = out.decode('latin1', errors='ignore')
    print(txt)
    mflag = re.search(r"flag\{[^}]+\}", txt)
    if not mflag:
        # maybe bytes literal
        mb = re.search(r"b'([^']+)'", txt)
        if mb:
            s = mb.group(1).encode('latin1', 'ignore').decode('unicode_escape', 'ignore')
            mf2 = re.search(r"flag\{[^}]+\}", s)
            if mf2:
                mflag = mf2
    if mflag:
        print('FLAG:', mflag.group(0))
    else:
        print('No flag parsed')

if __name__ == '__main__':
    solve()
